revision.text:
{{Navbox
| name       = Userspace disclaimers
| title      = Userspace messages and disclaimers
| bodyclass  = hlist
| state      = {{{state|autocollapse}}}

| group1     = User pages
| list1      =
* {{tl|This is a user page}}
* {{tl|User page}} ([[TM:User page mini|mini]])
* {{tl|Userpage bar}}
* {{tl|Userpageblue&round}}

| group2     = User talk pages
| list2      = 
* {{tl|Message}}
* {{tl|Not Christmas}}
* {{tl|Talk header}}
* {{tl|Talk header preload}}
* {{tl|Talkpagecool}}
* {{tl|User notification preference}}
* {{tl|User talk}}
* {{tl|User talk page mini}}
* {{tl|User talk-page header}}
* {{tl|User talk rules}}
* {{tl|User talk top}}
* {{tl|Usercomment}}
* {{tl|Usertalk bar}}
* {{tl|Usertalkback}}
* {{tl|Usertalkconcise}}
* {{tl|User talk criticism}}
* {{tl|Usertalksuper}}
* {{tl|Userwhisperback}}

|group3      = Editnotices
|list3       =
* {{tl|Editnotice userpage}}
* {{tl|User time zone editnotice}}

| group4     = Drafts and sandboxes
| list4      =
* {{tl|User sandbox}}
* {{tl|Userspace draft}}
* {{tl|Workpage}}
* {{tl|Userspace notes}}
* {{tl|Draft article}}
* ''See also:'' {{tl|Template draft}}
* {{tl|Draft RfC}}

| group5     = Blanking
| list5      =
* {{tl|Userpage blanked}}
* {{tl|Courtesy blanked}}
* {{tl|Intentionally blank}}

| belowstyle = font-weight:bold;
| below      = 
* {{icon|category}} [[:Category:User talk header templates|Category]]

}}<noinclude>
{{Documentation|content=
{{Collapsible option|statename=optional}}

[[Category:Documentation see also templates]]
}}
</noinclude>

